module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const mean = parseFloat(args.mean) || 0;
const sd = Math.abs(parseFloat(args.sd)) || 1;
const color = args.color || 'var(--accent-color)';
const showMean = String(args.showmean) !== 'false';
const align = String(args.align || 'center').toLowerCase();
const mw = Math.max(120, Math.min(1200, parseFloat(args.maxwidth) || 440));
const fillPct = Math.max(0, Math.min(100, Number.isFinite(parseFloat(args.fill)) ? parseFloat(args.fill) : 30));
const marginStr = align === 'left' ? '1rem auto 1rem 0' : align === 'right' ? '1rem 0 1rem auto' : '1rem auto';
const lo = mean - 3.6 * sd, hi = mean + 3.6 * sd, span = hi - lo;
const W = 100, H = 60, base = 56, peak = 50; // svg units
const gx = (v) => ((v - lo) / span) * W;
const g = (v) => Math.exp(-0.5 * Math.pow((v - mean) / sd, 2));
const N = 120;
const curve = [];
for (let i = 0; i <= N; i++) { const v = lo + span * i / N; curve.push([gx(v), base - peak * g(v)]); }
const linePath = 'M' + curve.map((p) => p[0].toFixed(2) + ',' + p[1].toFixed(2)).join(' L');
let shade = '';
const fromRaw = String(args.from ?? '').trim(), toRaw = String(args.to ?? '').trim();
if (fromRaw !== '' || toRaw !== '') {
  const a = fromRaw !== '' ? parseFloat(fromRaw) : lo;
  const b = toRaw !== '' ? parseFloat(toRaw) : hi;
  const s0 = Math.max(lo, Math.min(a, b)), s1 = Math.min(hi, Math.max(a, b));
  const pts = [];
  for (let i = 0; i <= N; i++) {
    const v = s0 + (s1 - s0) * i / N;
    pts.push([gx(v), base - peak * g(v)]);
  }
  const area = `M${gx(s0).toFixed(2)},${base} L` + pts.map((p) => p[0].toFixed(2) + ',' + p[1].toFixed(2)).join(' L') + ` L${gx(s1).toFixed(2)},${base} Z`;
  shade = `<path d="${area}" class="mdp-ds-fill"/>`;
  if (args.label) {
    const mid = gx((s0 + s1) / 2);
    shade += `<text x="${mid.toFixed(2)}" y="${(base - 2).toFixed(2)}" class="mdp-ds-lbl" text-anchor="middle">${esc(args.label)}</text>`;
  }
}
const meanLine = showMean ? `<line x1="${gx(mean).toFixed(2)}" y1="${(base - peak).toFixed(2)}" x2="${gx(mean).toFixed(2)}" y2="${base}" class="mdp-ds-mean"/>` : '';
const axis = `<line x1="0" y1="${base}" x2="${W}" y2="${base}" class="mdp-ds-axis"/>`;
return `\n\n<div class="mdp-mod-distribution" style="--ds-color:${color}; --ds-fill:${fillPct}%; width: min(100%, ${mw}px); margin:${marginStr};"><svg viewBox="0 0 ${W} ${H}" preserveAspectRatio="xMidYMid meet">` +
  `${shade}<path d="${linePath}" class="mdp-ds-curve"/>${meanLine}${axis}</svg></div>\n\n`;
